        ["Adhkar.AfterPrayer.1.Translation"] = "Pido perdón a Allah (tres veces)",
        ["Adhkar.AfterPrayer.2.Arabic"] = "اللَّهُمَّ أَنْتَ السَّلَامُ وَمِنْكَ السَّلَامُ، تَبَارَكْتَ يَا ذَا الْجَلَالِ وَالْإِكْرَامِ",
        ["Adhkar.AfterPrayer.2.Translation"] = "Oh Allah, Tú eres la Paz y de Ti viene la paz. Bendito seas, Oh Poseedor de la majestad y el honor.",
        ["Adhkar.AfterPrayer.3.Arabic"] = "سُبْحَانَ اللَّهِ · الْحَمْدُ لِلَّهِ · اللَّهُ أَكْبَرُ",
        ["Adhkar.AfterPrayer.3.Translation"] = "Gloria a Allah · Alabado sea Allah · Allah es el Más Grande",
        ["Adhkar.Morning"] = "Adhkar de la mañana",
